  ('heelevel3-6f0ba476-moex-00469', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '張木的妹妹張雲於110年時，年紀40歲，就讀於臺灣大學研究所，兼任助理年收入12萬，無其 他收入。若張木將張雲申報為扶養親屬，請問下述何者正確？', '["張雲為張木妹妹，因其屬成年，且有收入，故不可以列為扶養親屬", "張雲在學中，可列為扶養親屬。張雲的醫藥費可申報為列舉扣除額", "張雲在學中，可列為扶養親屬。張雲的人身保險費可申報為列舉扣除額", "張雲在學中，可列為扶養親屬。張雲的房租支出可申報為列舉扣除額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "2dd66111d1a6", "answer_pdf_sha1": "4da3144b64e9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
